    private func fetchAPI() async {
        errorText = nil
        isLoadingAPI = true
        defer { isLoadingAPI = false }

        do {
            let url = URL(string: "https://api.example.com")!
            let (data, response) = try await URLSession.shared.data(from: url)
            apiResponse = format(data: data, response: response)
        } catch {
            errorText = "API error: \(error.localizedDescription)"
